function runtimeBridgeSecretLike(value: string): boolean {
	return /(sk-[A-Za-z0-9_-]{10,}|ghp_[A-Za-z0-9_]{10,}|github_pat_[A-Za-z0-9_]{10,}|AKIA[0-9A-Z]{12,}|-----BEGIN [A-Z ]+PRIVATE KEY-----)/.test(value);
}

function buildProfessionalRuntimeBridgesGate(bridgeFilter?: string): ProfessionalRuntimeBridgesGateV1 {
	ensureReconStorage();
	const index = parseToolIndex();
	const corpus = [RECON_SYSTEM_PROMPT, RECON_APPEND_SYSTEM_PROMPT, JSON.stringify(PROFESSIONAL_RUNTIME_BRIDGE_MATRIX), buildToolDigest()].join("\n");
	const specs = bridgeFilter
		? PROFESSIONAL_RUNTIME_BRIDGE_MATRIX.filter((bridge) => bridge.id === bridgeFilter || bridge.id.includes(bridgeFilter))
		: PROFESSIONAL_RUNTIME_BRIDGE_MATRIX;
	const bridges = specs.map<ProfessionalRuntimeBridgeRowV1>((bridge) => {
		const presentPreferred = bridge.preferredTools.filter((tool) => indexedToolPresent(index, tool) === true);
		const presentFallbacks = bridge.fallbackTools.filter((tool) => indexedToolPresent(index, tool) === true);
		const missingPreferred = bridge.preferredTools.filter((tool) => indexedToolPresent(index, tool) !== true);
		const proofExitFound = bridge.proofExit.filter((marker) => corpus.includes(marker));
		const artifactPlanOk = bridge.artifactPlan.length >= 3 && bridge.artifactPlan.every((path) => path.startsWith(".repi/evidence") || path.startsWith(".repi/recon"));
		const envRefOnly = bridge.envRefs.every((ref) => /^[A-Z][A-Z0-9_]+$/.test(ref) && !runtimeBridgeSecretLike(ref));
		const executableTemplateCount = bridge.commandTemplates.filter((template) => /\bre_[a-z0-9_]+\b|\bcurl\b|\bfrida\b|\bgdb\b|\bpython3\b|\bnode\b/.test(template)).length;
		return {
			bridgeId: bridge.id,
			title: bridge.title,
			status: presentFallbacks.length > 0 ? "runtime-ready" : "blocked",
			domains: bridge.domains,
			preferredTools: bridge.preferredTools,
			fallbackTools: bridge.fallbackTools,
			presentPreferred,
			presentFallbacks,
			missingPreferred,
			fallback_available: presentFallbacks.length > 0,
			commandTemplates: bridge.commandTemplates,
			artifactPlan: bridge.artifactPlan,
			artifactPlanOk,
			envRefs: bridge.envRefs,
			envRefOnly,
			proofExit: bridge.proofExit,
			proofExitFound,
			proofExitMissing: bridge.proofExit.filter((marker) => !proofExitFound.includes(marker)),
			executableTemplateCount,
			narrativeOnly: executableTemplateCount === 0,
			nextRuntimeCommands: [
				"re_runtime_bridge refresh",
				`re_runtime_bridge show ${bridge.id}`,
				bridge.id === "web-cdp-replay" ? "re_live_browser run <url>" : undefined,
				bridge.id === "mobile-frida" ? "re_mobile_runtime run <package>" : undefined,
				bridge.id === "exploit-verifier-runtime" ? "re_exploit_lab run <target> 5" : undefined,
				"re_domain_proof_exit write <domain>",
			].filter((item): item is string => Boolean(item)),
		};
	});
	return {
		kind: "ProfessionalRuntimeBridgesGateV1",
		schemaVersion: 1,
		generatedAt: new Date().toISOString(),
		ProfessionalRuntimeBridgesGateV1: true,
		runtime: "runtime:professional-runtime-bridges",
		toolIndexPath: toolIndexPath(),
		requiredGates: ["professional_runtime_bridge_gate", "runtime_execution_bridge_matrix", "real_toolchain_bridge_contract", "exploit_verifier_runtime_contract", "web_cdp_replay_contract", "mobile_frida_dynamic_bridge_contract", "artifact_backed_tool_execution_plan", "env_ref_secret_boundary"],
		bridges,
		closure: {
			allBridgeSpecsPresent: bridges.length === PROFESSIONAL_RUNTIME_BRIDGE_MATRIX.length || Boolean(bridgeFilter),
			allFallbacksAvailable: bridges.every((bridge) => bridge.fallback_available),
			allHaveExecutableTemplates: bridges.every((bridge) => !bridge.narrativeOnly && bridge.executableTemplateCount >= 3),
			allHaveArtifactPlans: bridges.every((bridge) => bridge.artifactPlanOk),
			allHaveProofExitMappings: bridges.every((bridge) => bridge.proofExit.length >= 5 && bridge.proofExitMissing.length === 0),
			allEnvRefsSecretFree: bridges.every((bridge) => bridge.envRefOnly),
		},
		nextRuntimeCommands: ["re_runtime_bridge show", "re_runtime_bridge refresh", "re_runtime_bridge show web-cdp-replay", "re_runtime_bridge show mobile-frida", "re_exploit_lab run <target> 5", "re_live_browser run <url>", "re_mobile_runtime run <package>"],
		invariants: ["professional_runtime_bridge_gate", "runtime_execution_bridge_matrix", "real_toolchain_bridge_contract", "exploit_verifier_runtime_contract", "web_cdp_replay_contract", "mobile_frida_dynamic_bridge_contract", "artifact_backed_tool_execution_plan", "env_ref_secret_boundary", "narrative_only_bridge_rejected"],
	};
}

function writeProfessionalRuntimeBridgesArtifact(report: ProfessionalRuntimeBridgesGateV1): string {
	ensureReconStorage();
	const path = join(evidenceToolchainDir(), `${report.generatedAt.replace(/[:.]/g, "-")}-professional-runtime-bridges.md`);
	writeFileSync(path, `${formatProfessionalRuntimeBridgesGate(report, path)}\n\n## JSON\n\n\`\`\`json\n${JSON.stringify(report, null, 2)}\n\`\`\`\n`, "utf-8");
	appendEvidence({
		kind: "artifact",
		title: "professional-runtime-bridges",
		fact: `ProfessionalRuntimeBridgesGateV1 bridges=${report.bridges.length} fallback=${report.closure.allFallbacksAvailable} executable=${report.closure.allHaveExecutableTemplates}`,
		command: "re_runtime_bridge show",
		path,
		verify: `cat ${path}`,
		confidence: "runtime:professional-runtime-bridges runtime_execution_bridge_matrix artifact_backed_tool_execution_plan env_ref_secret_boundary",
	});
	return path;
}

function formatProfessionalRuntimeBridgesGate(report: ProfessionalRuntimeBridgesGateV1, path?: string): string {
	return [
		"professional_runtime_bridges:",
		"ProfessionalRuntimeBridgesGateV1: true",
		"runtime: runtime:professional-runtime-bridges",
		path ? `artifact: ${path}` : undefined,
		`tool_index: ${report.toolIndexPath}`,
		`closure: specs=${report.closure.allBridgeSpecsPresent} fallback=${report.closure.allFallbacksAvailable} executable=${report.closure.allHaveExecutableTemplates} artifact=${report.closure.allHaveArtifactPlans} proof=${report.closure.allHaveProofExitMappings} env_ref=${report.closure.allEnvRefsSecretFree}`,
		"bridges:",
		...report.bridges.flatMap((bridge) => [
			`- bridge:${bridge.bridgeId} status=${bridge.status} fallback_available=${bridge.fallback_available}`,
			`  domains: ${bridge.domains.join(", ")}`,
			`  preferred_present: ${bridge.presentPreferred.join(", ") || "none"}`,
			`  fallback_present: ${bridge.presentFallbacks.join(", ") || "none"}`,
			`  command_templates: ${bridge.commandTemplates.join(" | ")}`,
			`  artifact_plan: ${bridge.artifactPlan.join(" | ")}`,
			`  env_refs: ${bridge.envRefs.join(", ")}`,
			`  proof_exit: ${bridge.proofExit.join("; ")}`,
			`  next: ${bridge.nextRuntimeCommands.join(" | ")}`,
		]),
		"next_runtime_commands:",
		...report.nextRuntimeCommands.map((item) => `- ${item}`),
		"invariants:",
		...report.invariants.map((item) => `- ${item}`),
	].filter(Boolean).join("\n");
}

function buildProfessionalRuntimeBridgeOutput(action: "show" | "refresh" = "show", bridgeFilter?: string): string {
	if (action === "refresh") return buildToolDigest();
	const report = buildProfessionalRuntimeBridgesGate(bridgeFilter);
	const path = writeProfessionalRuntimeBridgesArtifact(report);
	return formatProfessionalRuntimeBridgesGate(report, path);
}




