function runtimeAdapterSecretLike(value: string): boolean {
	return /(sk-[A-Za-z0-9_-]{10,}|ghp_[A-Za-z0-9_]{10,}|github_pat_[A-Za-z0-9_]{10,}|AKIA[0-9A-Z]{12,}|-----BEGIN [A-Z ]+PRIVATE KEY-----)/.test(value);
}

function buildRuntimeAdapterExecutionGate(adapterFilter?: string): RuntimeAdapterExecutionGateV1 {
	ensureReconStorage();
	const index = parseToolIndex();
	const specs = adapterFilter
		? RUNTIME_ADAPTER_EXECUTION_MATRIX.filter((adapter) => adapter.id === adapterFilter || adapter.id.includes(adapterFilter) || adapter.domainId.includes(adapterFilter))
		: RUNTIME_ADAPTER_EXECUTION_MATRIX;
	const adapters = specs.map<RuntimeAdapterExecutionRowV1>((adapter) => {
		const present = indexedToolPresent(index, adapter.tool) === true;
		const fallbackPresent = indexedToolPresent(index, adapter.fallbackTool) === true;
		return {
			...adapter,
			adapterId: adapter.id,
			present,
			fallbackPresent,
			status: present ? "native-ready" : fallbackPresent ? "fallback-ready" : "blocked",
			runnerReady: adapter.commandTemplate.includes("adapter-") && adapter.fallbackCommandTemplate.includes("fallback"),
			parserReady: adapter.parserRules.length >= 2 && adapter.parserRules.every((rule) => rule.id.startsWith("parser-")),
			artifactIngestReady: adapter.artifactKinds.length >= 2 && adapter.ingestTargets.includes("evidence-ledger") && adapter.ingestTargets.includes("knowledge-graph") && adapter.ingestTargets.includes("memory-event"),
			proofExitReady: adapter.proofExitSignals.length >= 2,
			envRefOnly: adapter.envRefs.every((ref) => /^[A-Z][A-Z0-9_]+$/.test(ref) && !runtimeAdapterSecretLike(ref)),
			nextRuntimeCommands: [`re_runtime_adapter plan ${adapter.id} <target>`, `re_runtime_adapter run ${adapter.id} <target>`, "re_verifier matrix", `re_domain_proof_exit write ${adapter.domainId}`],
		};
	});
	return {
		kind: "RuntimeAdapterExecutionGateV1",
		schemaVersion: 1,
		generatedAt: new Date().toISOString(),
		RuntimeAdapterExecutionGateV1: true,
		runtime: "runtime:adapter-execution",
		toolIndexPath: toolIndexPath(),
		requiredGates: ["runtime_adapter_execution_gate", "adapter_runner_parser_ingest_contract", "r2_ghidra_native_adapter_contract", "frida_mobile_adapter_contract", "web_cdp_adapter_contract", "pwntools_exploit_verifier_adapter_contract", "tshark_pcap_adapter_contract", "binwalk_firmware_adapter_contract"],
		adapters,
		closure: {
			allAdapterSpecsPresent: adapters.length === RUNTIME_ADAPTER_EXECUTION_MATRIX.length || Boolean(adapterFilter),
			allHaveRunnerTemplates: adapters.every((adapter) => adapter.runnerReady),
			allHaveParserRules: adapters.every((adapter) => adapter.parserReady),
			allHaveArtifactKinds: adapters.every((adapter) => adapter.artifactKinds.length >= 2),
			allHaveIngestTargets: adapters.every((adapter) => adapter.artifactIngestReady),
			allHaveProofExitSignals: adapters.every((adapter) => adapter.proofExitReady),
			allHaveNativeOrFallbackTool: adapters.every((adapter) => adapter.present || adapter.fallbackPresent),
			allEnvRefsSecretFree: adapters.every((adapter) => adapter.envRefOnly),
		},
		nextRuntimeCommands: ["re_runtime_adapter show", "re_runtime_adapter plan r2-native-xref-adapter <target>", "re_runtime_adapter run web-cdp-network-adapter <url>", "re_runtime_adapter run frida-mobile-hook-adapter <package>", "npm run gate:runtime-adapter-execution"],
		invariants: ["runtime_adapter_execution_gate", "adapter_runner_parser_ingest_contract", "runner_output_parser_must_write_artifact", "artifact_ingest_target_must_include_evidence_knowledge_memory", "adapter_run_secret_literals_rejected"],
	};
}

function formatRuntimeAdapterExecutionGate(report: RuntimeAdapterExecutionGateV1, path?: string): string {
	return [
		"runtime_adapter_execution:",
		"RuntimeAdapterExecutionGateV1: true",
		"runtime: runtime:adapter-execution",
		path ? `artifact: ${path}` : undefined,
		`tool_index: ${report.toolIndexPath}`,
		`closure: specs=${report.closure.allAdapterSpecsPresent} runner=${report.closure.allHaveRunnerTemplates} parser=${report.closure.allHaveParserRules} artifact=${report.closure.allHaveArtifactKinds} ingest=${report.closure.allHaveIngestTargets} proof=${report.closure.allHaveProofExitSignals} fallback=${report.closure.allHaveNativeOrFallbackTool} env_ref=${report.closure.allEnvRefsSecretFree}`,
		"adapters:",
		...report.adapters.flatMap((adapter) => [
			`- adapter:${adapter.adapterId} bridge=${adapter.bridgeId} domain=${adapter.domainId} status=${adapter.status}`,
			`  runner_kind: ${adapter.runnerKind} tool=${adapter.tool} present=${adapter.present} fallback=${adapter.fallbackTool} fallback_present=${adapter.fallbackPresent}`,
			`  command_template: ${adapter.commandTemplate}`,
			`  fallback_template: ${adapter.fallbackCommandTemplate}`,
			`  parser_rules: ${adapter.parserRules.map((rule) => rule.id).join(", ")}`,
			`  artifact_kinds: ${adapter.artifactKinds.join(", ")}`,
			`  ingest_targets: ${adapter.ingestTargets.join(", ")}`,
			`  proof_exit_signals: ${adapter.proofExitSignals.join("; ")}`,
			`  env_refs: ${adapter.envRefs.join(", ")}`,
			`  next: ${adapter.nextRuntimeCommands.join(" | ")}`,
		]),
		"next_runtime_commands:",
		...report.nextRuntimeCommands.map((item) => `- ${item}`),
	].filter(Boolean).join("\n");
}

function writeRuntimeAdapterExecutionArtifact(report: RuntimeAdapterExecutionGateV1): string {
	ensureReconStorage();
	const path = join(evidenceToolchainDir(), `${report.generatedAt.replace(/[:.]/g, "-")}-runtime-adapter-execution.md`);
	writeFileSync(path, `${formatRuntimeAdapterExecutionGate(report, path)}\n\n## JSON\n\n\`\`\`json\n${JSON.stringify(report, null, 2)}\n\`\`\`\n`, "utf-8");
	appendEvidence({ kind: "artifact", title: "runtime-adapter-execution", fact: `RuntimeAdapterExecutionGateV1 adapters=${report.adapters.length} runner=${report.closure.allHaveRunnerTemplates} parser=${report.closure.allHaveParserRules} ingest=${report.closure.allHaveIngestTargets}`, command: "re_runtime_adapter show", path, verify: `cat ${path}`, confidence: "runtime:adapter-execution adapter_runner_parser_ingest_contract evidence-ledger knowledge-graph memory-event" });
	return path;
}

function materializeRuntimeAdapterCommand(template: string, target?: string): string {
	const targetValue = target?.trim() || ".";
	return template.replace(/^[^:]+:\s*/, "").replaceAll("<target>", shellQuote(targetValue));
}

function parseRuntimeAdapterSignals(adapter: RuntimeAdapterExecutionRowV1, combinedOutput: string): RuntimeAdapterExecutionArtifactV1["parserSignals"] {
	return adapter.parserRules.map((rule) => {
		let matches: string[] = [];
		try {
			const regex = new RegExp(rule.regex, "gi");
			matches = Array.from(combinedOutput.matchAll(regex)).map((match) => truncateMiddle(match[0], 180)).slice(0, 12);
		} catch (error) {
			matches = [`parser_error=${error instanceof Error ? error.message : String(error)}`];
		}
		return { ruleId: rule.id, proofExitSignal: rule.proofExitSignal, matches };
	});
}

function formatRuntimeAdapterExecutionArtifact(artifact: RuntimeAdapterExecutionArtifactV1, path?: string): string {
	return [
		"runtime_adapter_run:",
		"RuntimeAdapterExecutionArtifactV1: true",
		path ? `artifact: ${path}` : undefined,
		`adapter: ${artifact.adapterId}`,
		`domain: ${artifact.domainId}`,
		`bridge: ${artifact.bridgeId}`,
		`target: ${artifact.target ?? "<none>"}`,
		`runner: ${artifact.selectedRunner}`,
		`exit: ${artifact.exitCode} killed=${artifact.killed}`,
		`stdout_sha256: ${artifact.stdoutSha256}`,
		`stderr_sha256: ${artifact.stderrSha256}`,
		`command: ${artifact.command}`,
		"parser_signals:",
		...artifact.parserSignals.map((signal) => `- ${signal.ruleId} => ${signal.proofExitSignal}: ${signal.matches.join(" | ") || "no-match"}`),
		`artifact_kinds: ${artifact.artifactKinds.join(", ")}`,
		`ingest_targets: ${artifact.ingestTargets.join(", ")}`,
		`proof_exit_signals: ${artifact.proofExitSignals.join("; ")}`,
	].filter(Boolean).join("\n");
}

async function runRuntimeAdapterExecution(pi: ExtensionAPI, options: { adapter?: string; target?: string; timeoutMs?: number }): Promise<string> {
	const report = buildRuntimeAdapterExecutionGate(options.adapter);
	const adapter = report.adapters.find((row) => row.adapterId === options.adapter) ?? report.adapters[0];
	if (!adapter) return "runtime_adapter_execution:\nstatus: missing\nnext: re_runtime_adapter show";
	if (!options.target?.trim()) return `${formatRuntimeAdapterExecutionGate(report)}\n\nblocked: target_required\nnext: re_runtime_adapter run ${adapter.adapterId} <target>`;
	const selectedRunner = adapter.present ? "native" : "fallback";
	const selectedTemplate = selectedRunner === "native" ? adapter.commandTemplate : adapter.fallbackCommandTemplate;
	const command = materializeRuntimeAdapterCommand(selectedTemplate, options.target);
	const timeout = Math.max(5000, Math.min(options.timeoutMs ?? Number(process.env.REPI_RUNTIME_ADAPTER_TIMEOUT_MS ?? 60000), 600000));
	const startedAt = new Date().toISOString();
	const result = await pi.exec("bash", ["-lc", `set +e\nexport REPI_ADAPTER_TARGET=${shellQuote(options.target)}\n${command}`], { timeout });
	const finishedAt = new Date().toISOString();
	const combined = `${result.stdout}\n${result.stderr}`;
	const artifact: RuntimeAdapterExecutionArtifactV1 = {
		kind: "RuntimeAdapterExecutionArtifactV1",
		schemaVersion: 1,
		adapterId: adapter.adapterId,
		domainId: adapter.domainId,
		bridgeId: adapter.bridgeId,
		target: options.target,
		startedAt,
		finishedAt,
		selectedRunner,
		command,
		exitCode: result.code,
		killed: result.killed,
		stdoutSha256: sha256Text(result.stdout),
		stderrSha256: sha256Text(result.stderr),
		parserSignals: parseRuntimeAdapterSignals(adapter, combined),
		artifactKinds: adapter.artifactKinds,
		ingestTargets: adapter.ingestTargets,
		proofExitSignals: adapter.proofExitSignals,
	};
	const dir = join(evidenceToolchainDir(), "runtime-adapters", adapter.adapterId);
	mkdirSync(dir, { recursive: true });
	const path = join(dir, `${startedAt.replace(/[:.]/g, "-")}.json`);
	writeFileSync(path, `${JSON.stringify({ ...artifact, stdoutHead: truncateMiddle(result.stdout, 8000), stderrHead: truncateMiddle(result.stderr, 4000) }, null, 2)}\n`, "utf-8");
	appendEvidence({ kind: "runtime", title: `runtime-adapter ${adapter.adapterId}`, fact: `RuntimeAdapterExecutionGateV1 adapter=${adapter.adapterId} runner=${selectedRunner} exit=${result.code} parser_matches=${artifact.parserSignals.reduce((sum, row) => sum + row.matches.length, 0)} ingest=evidence-ledger,knowledge-graph,memory-event`, command: `re_runtime_adapter run ${adapter.adapterId} ${options.target}`, path, verify: `cat ${path}`, confidence: "runtime:adapter-execution adapter_runner_parser_ingest_contract runner_output_parser_must_write_artifact" });
	return formatRuntimeAdapterExecutionArtifact(artifact, path);
}


