export function createReconExtensionFactory() {
	return function reconExtension(pi: ExtensionAPI): void {
		ensureReconStorage();
		const stats: ReconStats = {
			calls: 0,
			bashCalls: 0,
			failures: 0,
			repeatedCommandCount: 0,
			lastCommands: [],
			active: false,
			selfReviewDue: false,
		};
		const compactAutoResumeIds = new Set<string>();
		let compactAutoResumeBudget = 3;

		pi.on("session_start", async (_event, ctx) => {
			ensureReconStorage();
			if (ctx.hasUI) ctx.ui.setStatus("pi-recon", "REPI kernel profile ready");
		});

		pi.on("before_agent_start", async (event, ctx) => {
			if (!isSecurityTask(event.prompt)) return;
			const route = routeReconTask(event.prompt);
			const mission = writeCurrentMission(createMission(event.prompt, route));
			stats.active = true;
			stats.lastRoute = route;
			stats.currentMissionId = mission.id;
			pi.appendEntry("pi-recon-route", { timestamp: Date.now(), route, prompt: truncateMiddle(event.prompt, 2000) });
			pi.appendEntry("pi-recon-mission", { timestamp: Date.now(), mission });
			if (!pi.getSessionName()) pi.setSessionName(`REPI: ${route.domain}`);
			if (ctx.hasUI) ctx.ui.setStatus("pi-recon", formatRoute(route));
			const packet = [
				"## REPI Runtime Packet",
				formatRoute(route),
				`skill_hint: ${route.skillHint}`,
				"workflow:",
				...route.workflow.map((step) => `- ${step}`),
				"",
				"Mission blackboard:",
				buildMissionDigest(),
				"",
				"Execution kernel:",
				buildKernelOutput("build", { target: event.prompt }),
				"",
				"Decision core:",
				buildDecisionCoreOutput("tick", { target: event.prompt }),
				"",
				"Evidence ledger status:",
				buildStartupEvidenceDigest({ target: event.prompt }),
				"",
				"Memory status:",
				buildStartupMemoryDigest({ route: route.domain, target: event.prompt }),
				"",
				"Context/resume status:",
				buildStartupContextDigest({ route: route.domain, target: event.prompt }),
				"",
				"Tool index digest:",
				buildToolDigest(),
				"",
				"Completion gate audit:",
				formatCompletionAudit(),
				"",
				"Execution constraints:",
				"- Start with passive mapping and one live path proof.",
				"- Record decisive evidence in one block.",
				"- If failures or repetition appear, change method instead of repeating.",
				"- If a required tool is missing, plan/install through re_bootstrap and refresh tool-index.",
				"- Before claiming completion, satisfy or explicitly explain every re_complete gate.",
				stats.selfReviewDue ? makeSelfReview(stats) : "",
			].join("\n");
			stats.selfReviewDue = false;
			return { systemPrompt: `${event.systemPrompt}\n\n${packet}` };
		});

		pi.on("tool_call", async (event) => {
			try {
				appendToolCallTraceFromCall(event, stats.currentMissionId);
			} catch (error) {
				pi.appendEntry("repi-tool-call-trace-error", { timestamp: Date.now(), error: String(error).slice(0, 500) });
			}
			const command = getBashCommand(event);
			if (!command) return;
			stats.bashCalls += 1;
			const hash = createHash("sha256").update(command).digest("hex");
			stats.repeatedCommandCount = stats.lastCommandHash === hash ? stats.repeatedCommandCount + 1 : 1;
			stats.lastCommandHash = hash;
			stats.lastCommands.push(command);
			stats.lastCommands = stats.lastCommands.slice(-8);
			if (stats.active && stats.repeatedCommandCount >= 3) {
				stats.selfReviewDue = true;
				return {
					block: true,
					reason:
						"REPI loop guard: same bash command repeated 3 times. Run /re-self-review or change evidence surface/tool/arguments.",
				};
			}
		});

		pi.on("tool_result", async (event, ctx) => {
			try {
				appendToolCallTraceFromResult(event, stats.currentMissionId);
			} catch (error) {
				pi.appendEntry("repi-tool-result-trace-error", { timestamp: Date.now(), error: String(error).slice(0, 500) });
			}
			stats.calls += 1;
			if (event.isError) stats.failures += 1;
			const memorySettings = repiMemorySettings();
			if (stats.active && event.toolName !== "re_memory" && memorySettings.autoDepositMode !== "off") {
				try {
					const text = textBlocksToString(event.content);
					const command = getToolResultCommand(event);
					if (shouldAutoDepositToolResult(event, text, command, memorySettings)) {
						appendMemoryDepositionRuntimeEvent(
							{
								stage: event.toolName === "bash" ? "shell" : "tool",
								source: `tool_result:${event.toolName}`,
								status: event.isError ? "blocked" : "written",
								task: `runtime tool result: ${event.toolName}`,
								route: stats.lastRoute?.domain ?? "runtime",
								command,
								stdout: text,
								outcome: event.isError ? "failure" : "partial",
								confidence: event.isError ? 0.66 : 0.58,
								lessons: [truncateMiddle(text || `${event.toolName} completed`, 900)],
								failurePatterns: event.isError
									? [truncateMiddle(text || `${event.toolName} failed`, 900)]
									: [],
								reuseRules: event.isError
									? []
									: [`reuse ${event.toolName} only with bound artifact/evidence hash`],
								commands: command ? [command] : [],
								reason: "high-value scoped auto writeback from REPI runtime hook",
							},
							{ writeback: true },
						);
					}
				} catch (error) {
					pi.appendEntry("repi-memory-deposition-error", { timestamp: Date.now(), error: String(error).slice(0, 500) });
				}
			}
			if (stats.active && stats.calls > 0 && stats.calls % 5 === 0) {
				stats.selfReviewDue = true;
				pi.appendEntry("pi-recon-self-review-due", { timestamp: Date.now(), stats: { ...stats } });
				if (ctx.hasUI) ctx.ui.notify("REPI self-review checkpoint is due", "info");
			}
			if (stats.active && event.toolName === "bash") {
				const text = textBlocksToString(event.content);
				if (/command not found|not recognized|No such file|cannot stat|ModuleNotFoundError|ImportError/i.test(text))
					stats.selfReviewDue = true;
			}
		});

		pi.on("session_before_compact", async (event) => {
			const contextPack = buildContextPack({ mode: "pack" });
			const contextPath = writeContextPackArtifact(contextPack);
			const details = buildReconCompactionDetails(contextPack, contextPath);
			const summary = buildReconCompactionSummary({ event, contextPack, contextPath });
			pi.appendEntry("pi-recon-compaction-checkpoint", {
				timestamp: Date.now(),
				tokensBefore: event.preparation.tokensBefore,
				firstKeptEntryId: event.preparation.firstKeptEntryId,
				policy:
					"REPI owned compaction: preserve goal, route, evidence, commands, files, unresolved assumptions, dispatcher budgets, and next steps.",
				thresholdPolicy:
					"triggerPercent/warningPercent from settings.compaction; compactionTriggerTokens = min(contextWindow * triggerPercent / 100, contextWindow - reserveTokens)",
				mission: readCurrentMission(),
				evidenceTail: truncateMiddle(buildContextEvidenceTail({ target: contextPack.target }), 3000),
				contextPath,
				compactionKind: details.kind,
				resumeCommand: details.resumeCommand,
				nextCommands: contextPack.nextCommands,
			});
			return {
				compaction: {
					summary,
					firstKeptEntryId: event.preparation.firstKeptEntryId,
					tokensBefore: event.preparation.tokensBefore,
					details,
				},
			};
		});

		pi.on("session_compact", async (event, ctx) => {
			const contract = buildReconCompactionResumeContract({
				compactionEntry: event.compactionEntry,
				fromExtension: event.fromExtension,
			});
			pi.appendEntry("pi-recon-compaction-resume-contract", contract);
			updateMissionGate(
				"compaction_resume_contract_ready",
				contract.verified ? "done" : "pending",
				contract.contextPath ?? "missing context path",
			);
			const resumeId = contract.compactionEntryId ?? `${contract.firstKeptEntryId}:${contract.tokensBefore}`;
			const canAutoResume = contract.verified && compactAutoResumeBudget > 0 && !compactAutoResumeIds.has(resumeId);
			const autoResume = buildReconCompactionAutoResume(
				contract,
				canAutoResume,
				canAutoResume
					? "verified contract; trigger bounded resume turn"
					: !contract.verified
						? "contract not verified"
						: compactAutoResumeIds.has(resumeId)
							? "already triggered for compaction entry"
							: "auto-resume budget exhausted",
			);
			pi.appendEntry("pi-recon-compaction-auto-resume", autoResume);
			const telemetry = initialReconCompactionResumeTelemetry(contract, autoResume);
			const telemetryPath = writeReconCompactionResumeTelemetry(telemetry);
			pi.appendEntry("pi-recon-compaction-resume-telemetry", { ...telemetry, path: telemetryPath });
			if (canAutoResume) {
				compactAutoResumeIds.add(resumeId);
				compactAutoResumeBudget -= 1;
				pi.sendMessage(
					{
						customType: "pi-recon-auto-resume",
						content: reconCompactionAutoResumePrompt(contract),
						display: true,
						details: autoResume,
					},
					{ triggerTurn: true },
				);
			}
			if (ctx.hasUI) {
				ctx.ui.setStatus(
					"pi-recon",
					`REPI compact resume ${canAutoResume ? "triggered" : contract.verified ? "ready" : "needs review"}`,
				);
			}
		});

		installReconCommands(pi, stats);
		installReconTools(pi);
	};
}

function builtinReconSkill(): Skill {
	ensureReconStorage();
	const filePath = builtinSkillFilePath();
	return {
		name: "reverse-pentest-orchestrator",
		description:
			"Built-in REPI orchestrator for reverse engineering, CTF, pwn, web/API security, JS signing, mobile, firmware, cloud/container, identity/AD, DFIR, malware-analysis, and agent-security tasks.",
		filePath,
		baseDir: join(reconDir(), "builtin", "reverse-pentest-orchestrator"),
		sourceInfo: createSyntheticSourceInfo(filePath, { source: RECON_SOURCE, scope: "temporary" }),
		disableModelInvocation: false,
	};
}

function builtinReconPrompts(): PromptTemplate[] {
	ensureReconStorage();
	return RECON_PROMPTS.map((prompt) => {
		const filePath = builtinPromptFilePath(prompt.name);
		return {
			...prompt,
			filePath,
			sourceInfo: createSyntheticSourceInfo(filePath, {
				source: RECON_SOURCE,
				scope: "temporary",
				baseDir: RECON_PROMPT_BASE,
			}),
		};
	});
}

export function createReconResourceLoaderOptions(): Partial<DefaultResourceLoaderOptions> {
	return {
		extensionsOverride: suppressLegacyReconConflicts,
		skillsOverride: (base) => {
			if (base.skills.some((skill) => skill.name === "reverse-pentest-orchestrator")) return base;
			return { skills: [builtinReconSkill(), ...base.skills], diagnostics: base.diagnostics };
		},
		promptsOverride: (base) => {
			const existing = new Set(base.prompts.map((prompt) => prompt.name));
			const additions = builtinReconPrompts().filter((prompt) => !existing.has(prompt.name));
			return { prompts: [...additions, ...base.prompts], diagnostics: base.diagnostics };
		},
	};
}
